window.translateInline = async (btnElement, originalText) => {
    try {
        btnElement.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
        
        const isArabic = /[\u0600-\u06FF]/.test(originalText);
        const langPair = isArabic ? 'ar|en' : 'en|ar';
        
        const response = await fetch(`https://api.mymemory.translated.net/get?q=${encodeURIComponent(originalText)}&langpair=${langPair}`);
        const data = await response.json();
        
        if (data && data.responseData && data.responseData.translatedText) {
            const translation = data.responseData.translatedText;
            const container = btnElement.parentElement;
            
            const transDiv = document.createElement('div');
            transDiv.className = 'mt-2 p-2 bg-blue-50 dark:bg-blue-900/20 border-l-2 border-blue-500 rounded text-sm text-gray-700 dark:text-gray-300';
            transDiv.innerHTML = `<span class="font-bold text-blue-600 dark:text-blue-400 text-xs">${isArabic ? 'English Translation:' : 'الترجمة العربية:'}</span><br>${escapeHTML(translation)}`;
            
            container.appendChild(transDiv);
            btnElement.remove();
        } else {
            btnElement.innerHTML = 'Error translating';
            setTimeout(() => { btnElement.innerHTML = isArabic ? 'Translate to English' : 'ترجمة إلى العربية'; }, 2000);
        }
    } catch(e) {
        console.error('Translation error', e);
        btnElement.innerHTML = 'Error';
    }
};

window.renderTranslationButton = (text) => {
    if (!text) return '';
    const isArabic = /[\u0600-\u06FF]/.test(text);
    const hasEnglish = /[a-zA-Z]/.test(text);
    
    if (window.currentLang === 'en' && isArabic) {
        return `<div class="mt-1"><button type="button" onclick="window.translateInline(this, '${escapeHTML(text).replace(/'/g, "\\'")}')" class="text-blue-500 hover:text-blue-700 underline text-[11px] font-bold cursor-pointer transition"><i class="fa-solid fa-language mx-1"></i>Translate to English</button></div>`;
    } else if (window.currentLang === 'ar' && hasEnglish && !isArabic) {
        return `<div class="mt-1"><button type="button" onclick="window.translateInline(this, '${escapeHTML(text).replace(/'/g, "\\'")}')" class="text-blue-500 hover:text-blue-700 underline text-[11px] font-bold cursor-pointer transition"><i class="fa-solid fa-language mx-1"></i>ترجمة إلى العربية</button></div>`;
    }
    return '';
};


        function escapeHTML(str) {
            if (!str) return '';
            return str.replace(/[&<>'"]/g, 
                tag => ({
                    '&': '&amp;',
                    '<': '&lt;',
                    '>': '&gt;',
                    "'": '&#39;',
                    '"': '&quot;'
                }[tag])
            );
        }

